import{c as e,Q as i,j as a,m as r}from"./chunks/framework.BIBjCrbN.js";const u=JSON.parse('{"title":"研究方向总览","description":"四大研究方向概览，提供按方向检索导师的入口","frontmatter":{"title":"研究方向总览","description":"四大研究方向概览，提供按方向检索导师的入口"},"headers":[],"relativePath":"research-directions/index.md","filePath":"research-directions/index.md","lastUpdated":1780110618000}'),l={name:"research-directions/index.md"};function d(o,t,s,n,h,c){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="研究方向总览" tabindex="-1">研究方向总览 <a class="header-anchor" href="#研究方向总览" aria-label="Permalink to &quot;研究方向总览&quot;">​</a></h1><h2 id="四大研究方向" tabindex="-1">四大研究方向 <a class="header-anchor" href="#四大研究方向" aria-label="Permalink to &quot;四大研究方向&quot;">​</a></h2><h3 id="_1-神经工程-脑机接口-bci" tabindex="-1">1. <a href="/apply-phd/research-directions/bci">神经工程 / 脑机接口 (BCI)</a> <a class="header-anchor" href="#_1-神经工程-脑机接口-bci" aria-label="Permalink to &quot;1. [神经工程 / 脑机接口 (BCI)](/research-directions/bci)&quot;">​</a></h3><p>脑机接口技术涉及神经信号的采集、解码与反馈，是神经科学与工程技术的交叉前沿。</p><p><strong>子方向</strong>：</p><ul><li>侵入式BCI（微电极阵列、ECoG）</li><li>非侵入式BCI（EEG、fNIRS）</li><li>神经信号处理与解码算法</li><li>神经调控（DBS、TMS、tACS）</li><li>闭环神经反馈系统</li><li>神经假体与康复工程</li></ul><p><strong>相关院校</strong>：清华、浙大、天大、中科院自动化所、上交</p><h3 id="_2-生物医学工程-bme" tabindex="-1">2. <a href="/apply-phd/research-directions/bme">生物医学工程 (BME)</a> <a class="header-anchor" href="#_2-生物医学工程-bme" aria-label="Permalink to &quot;2. [生物医学工程 (BME)](/research-directions/bme)&quot;">​</a></h3><p>生物医学工程将工程学原理应用于医学和生物领域，涵盖从分子到器官尺度的技术开发。</p><p><strong>子方向</strong>：</p><ul><li>医疗器械与系统</li><li>生物材料与组织工程</li><li>生物力学</li><li>康复工程</li><li>生物传感器与微流控</li><li>医学影像设备</li></ul><p><strong>相关院校</strong>：上交、华科、东南、北航、川大</p><h3 id="_3-神经科学-基础与临床" tabindex="-1">3. <a href="/apply-phd/research-directions/neuroscience">神经科学（基础与临床）</a> <a class="header-anchor" href="#_3-神经科学-基础与临床" aria-label="Permalink to &quot;3. [神经科学（基础与临床）](/research-directions/neuroscience)&quot;">​</a></h3><p>研究神经系统的结构、功能、发育和病理，从分子层面到系统层面理解大脑。</p><p><strong>子方向</strong>：</p><ul><li>系统神经科学（感觉、运动、认知回路）</li><li>细胞与分子神经科学</li><li>神经发育与可塑性</li><li>神经退行性疾病（阿尔茨海默病、帕金森病）</li><li>神经精神疾病</li><li>计算神经科学</li></ul><p><strong>相关院校</strong>：北大、复旦、中科院神经所、浙大</p><h3 id="_4-医学物理-影像" tabindex="-1">4. <a href="/apply-phd/research-directions/medical-physics">医学物理 / 影像</a> <a class="header-anchor" href="#_4-医学物理-影像" aria-label="Permalink to &quot;4. [医学物理 / 影像](/research-directions/medical-physics)&quot;">​</a></h3><p>运用物理学原理和方法解决医学问题，涵盖成像、治疗和测量技术。</p><p><strong>子方向</strong>：</p><ul><li>磁共振成像 (MRI)</li><li>超声成像与治疗</li><li>光学成像（双光子/共聚焦/近红外）</li><li>核医学与PET</li><li>放射治疗物理</li><li>医学图像处理与分析</li></ul><p><strong>相关院校</strong>：华科、东南、中山、中科大</p><h2 id="你的背景匹配度分析" tabindex="-1">你的背景匹配度分析 <a class="header-anchor" href="#你的背景匹配度分析" aria-label="Permalink to &quot;你的背景匹配度分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>匹配度</th><th>说明</th></tr></thead><tbody><tr><td>神经工程/BCI</td><td>⭐⭐⭐⭐⭐</td><td>本科BCI项目 + 硕士神经技术方向，直接对口</td></tr><tr><td>生物医学工程</td><td>⭐⭐⭐⭐</td><td>硕士BME专业，RA经验，硬件+软件能力</td></tr><tr><td>神经科学</td><td>⭐⭐⭐⭐</td><td>脑类器官研究经验，湿实验室技能，需补充分子生物学知识</td></tr><tr><td>医学物理/影像</td><td>⭐⭐⭐</td><td>本科医学物理基础，硕士钙成像经验，需补充更多实践经验</td></tr></tbody></table>',24)])])}const _=e(l,[["render",d]]);export{u as __pageData,_ as default};
